try {
const pages = $input.first().json.pages || [];
const markdown = pages.map(p => p.markdown).join('\n\n---PÁGINA---\n\n');

const systemPrompt = `Você é especialista em extração de dados de documentos financeiros (contas, boletos, faturas de consumo).

RETORNE SOMENTE JSON válido, sem markdown, sem blocos de código.

Schema obrigatório:
{
  "data_vencimento": "dd/MM/yyyy ou null",
  "numero_fatura": "identificador da fatura ou null",
  "destinatario_cobranca": "nome da empresa ou pessoa que emitiu a cobrança",
  "total": 0.00
}

Regras:
- destinatario_cobranca é OBRIGATÓRIO — empresa emissora (ex: Sabesp, Enel, Vivo, Copel)
- total é OBRIGATÓRIO — valor numérico puro sem R$ ou símbolos
- data_vencimento: formato dd/MM/yyyy; se não encontrar, use null
- numero_fatura: código ou número identificador; se não encontrar, use null
- Retorne APENAS o JSON, nada mais`;

return [{
  json: {
    request_body: {
      model: 'gpt-4.1',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: markdown }
      ],
      max_tokens: 500
    }
  }
}];
} catch (e) {
  return [{ json: { success: false, error_code: 'CODE_ERROR', message: '[FN - Prepara Extração] ' + (e.message || 'Erro desconhecido') } }];
}

try {
const raw = $input.first().json;

let content = '';
try {
  content = raw.choices[0].message.content;
} catch(e) {
  return [{ json: {
    extracao_ok: false,
    error_code: 'EXTRACAO_ERROR',
    message: 'Resposta inesperada da API: ' + JSON.stringify(raw).substring(0, 300)
  }}];
}

content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch(e) {
  return [{ json: {
    extracao_ok: false,
    error_code: 'EXTRACAO_ERROR',
    message: 'JSON inválido retornado pelo LLM: ' + content.substring(0, 300)
  }}];
}

if (!parsed.destinatario_cobranca || parsed.total === undefined || parsed.total === null) {
  return [{ json: {
    extracao_ok: false,
    error_code: 'EXTRACAO_ERROR',
    message: 'Campos obrigatórios ausentes: destinatario_cobranca e/ou total'
  }}];
}

const hoje = new Date();
const hojeFormatado = String(hoje.getDate()).padStart(2,'0') + '/' +
  String(hoje.getMonth()+1).padStart(2,'0') + '/' + hoje.getFullYear();

return [{ json: {
  extracao_ok: true,
  data_vencimento: parsed.data_vencimento || hojeFormatado,
  numero_fatura:   parsed.numero_fatura   || 'N/A',
  destinatario_cobranca: parsed.destinatario_cobranca,
  total: Number(parsed.total) || 0
}}];
} catch (e) {
  return [{ json: { extracao_ok: false, error_code: 'CODE_ERROR', message: '[FN - Parseia Extração] ' + (e.message || 'Erro desconhecido') } }];
}

